9224 bool BoUpSLP::isLoadCombineReductionCandidate(RecurKind RdxKind) const {
9225   if (RdxKind != RecurKind::Or)
9226     return false;
9227 
9228   unsigned NumElts = VectorizableTree[0]->Scalars.size();
9229   Value *FirstReduced = VectorizableTree[0]->Scalars[0];
9230   return isLoadCombineCandidateImpl(FirstReduced, NumElts, TTI,
9231                                     /* MatchOr */ false);
