12673 namespace {
12674 /// Data type for handling buildvector sequences with the reused scalars from
12675 /// other tree entries.
12676 struct ShuffledInsertData {
12677   /// List of insertelements to be replaced by shuffles.
12678   SmallVector<InsertElementInst *> InsertElements;
12679   /// The parent vectors and shuffle mask for the given list of inserts.
12680   MapVector<Value *, SmallVector<int>> ValueMasks;
12681 };
