12684 Value *BoUpSLP::vectorizeTree(
12685     const ExtraValueToDebugLocsMap &ExternallyUsedValues,
12686     SmallVectorImpl<std::pair<Value *, Value *>> &ReplacedExternals,
12687     Instruction *ReductionRoot) {
12688   // All blocks must be scheduled before any instructions are inserted.
12689   for (auto &BSIter : BlocksSchedules) {
12690     scheduleBlock(BSIter.second.get());
12691   }
12692   // Clean Entry-to-LastInstruction table. It can be affected after scheduling,
12693   // need to rebuild it.
12694   EntryToLastInstruction.clear();
12695 
12696   if (ReductionRoot)
12697     Builder.SetInsertPoint(ReductionRoot->getParent(),
12698                            ReductionRoot->getIterator());
12699   else
12700     Builder.SetInsertPoint(&F->getEntryBlock(), F->getEntryBlock().begin());
12701 
12702   // Postpone emission of PHIs operands to avoid cyclic dependencies issues.
12703   (void)vectorizeTree(VectorizableTree[0].get(), /*PostponedPHIs=*/true);
12704   for (const std::unique_ptr<TreeEntry> &TE : VectorizableTree)
12705     if (TE->State == TreeEntry::Vectorize &&
12706         TE->getOpcode() == Instruction::PHI && !TE->isAltShuffle() &&
12707         TE->VectorizedValue)
12708       (void)vectorizeTree(TE.get(), /*PostponedPHIs=*/false);
12709   // Run through the list of postponed gathers and emit them, replacing the temp
12710   // emitted allocas with actual vector instructions.
12711   ArrayRef<const TreeEntry *> PostponedNodes = PostponedGathers.getArrayRef();
12712   DenseMap<Value *, SmallVector<TreeEntry *>> PostponedValues;
12713   for (const TreeEntry *E : PostponedNodes) {
12714     auto *TE = const_cast<TreeEntry *>(E);
12715     if (auto *VecTE = getTreeEntry(TE->Scalars.front()))
12716       if (VecTE->isSame(TE->UserTreeIndices.front().UserTE->getOperand(
12717               TE->UserTreeIndices.front().EdgeIdx)))
12718         // Found gather node which is absolutely the same as one of the
12719         // vectorized nodes. It may happen after reordering.
12720         continue;
12721     auto *PrevVec = cast<Instruction>(TE->VectorizedValue);
12722     TE->VectorizedValue = nullptr;
