2887     Last->Idx = VectorizableTree.size() - 1;
2888     Last->State = EntryState;
2889     Last->ReuseShuffleIndices.append(ReuseShuffleIndices.begin(),
2890                                      ReuseShuffleIndices.end());
2891     if (ReorderIndices.empty()) {
2892       Last->Scalars.assign(VL.begin(), VL.end());
2893       Last->setOperations(S);
2894     } else {
2895       // Reorder scalars and build final mask.
2896       Last->Scalars.assign(VL.size(), nullptr);
2897       transform(ReorderIndices, Last->Scalars.begin(),
2898                 [VL](unsigned Idx) -> Value * {
2899                   if (Idx >= VL.size())
2900                     return UndefValue::get(VL.front()->getType());
2901                   return VL[Idx];
2902                 });
2903       InstructionsState S = getSameOpcode(Last->Scalars, *TLI);
2904       Last->setOperations(S);
2905       Last->ReorderIndices.append(ReorderIndices.begin(), ReorderIndices.end());
2906     }
2907     if (Last->State != TreeEntry::NeedToGather) {
2908       for (Value *V : VL) {
2909         const TreeEntry *TE = getTreeEntry(V);
2910         assert((!TE || TE == Last || doesNotNeedToBeScheduled(V)) &&
