2915           continue;
2916         }
2917         ScalarToTreeEntry[V] = Last;
2918       }
2919       // Update the scheduler bundle to point to this TreeEntry.
2920       ScheduleData *BundleMember = *Bundle;
2921       assert((BundleMember || isa<PHINode>(S.MainOp) ||
2922               isVectorLikeInstWithConstOps(S.MainOp) ||
2923               doesNotNeedToSchedule(VL)) &&
2924              "Bundle and VL out of sync");
2925       if (BundleMember) {
2926         for (Value *V : VL) {
