3804 /// Reorders the given \p Order according to the given \p Mask. \p Order - is
3805 /// the original order of the scalars. Procedure transforms the provided order
3806 /// in accordance with the given \p Mask. If the resulting \p Order is just an
3807 /// identity order, \p Order is cleared.
3808 static void reorderOrder(SmallVectorImpl<unsigned> &Order, ArrayRef<int> Mask,
3809                          bool BottomOrder = false) {
3810   assert(!Mask.empty() && "Expected non-empty mask.");
3811   unsigned Sz = Mask.size();
3812   if (BottomOrder) {
3813     SmallVector<unsigned> PrevOrder;
3814     if (Order.empty()) {
3815       PrevOrder.resize(Sz);
3816       std::iota(PrevOrder.begin(), PrevOrder.end(), 0);
3817     } else {
3818       PrevOrder.swap(Order);
3819     }
3820     Order.assign(Sz, Sz);
3821     for (unsigned I = 0; I < Sz; ++I)
3822       if (Mask[I] != PoisonMaskElem)
3823         Order[I] = PrevOrder[Mask[I]];
3824     if (all_of(enumerate(Order), [&](const auto &Data) {
3825           return Data.value() == Sz || Data.index() == Data.value();
3826         })) {
3827       Order.clear();
3828       return;
3829     }
3830     fixupOrderingIndices(Order);
3831     return;
3832   }
3833   SmallVector<int> MaskOrder;
3834   if (Order.empty()) {
3835     MaskOrder.resize(Sz);
3836     std::iota(MaskOrder.begin(), MaskOrder.end(), 0);
3837   } else {
3838     inversePermutation(Order, MaskOrder);
3839   }
3840   reorderReuses(MaskOrder, Mask);
3841   if (ShuffleVectorInst::isIdentityMask(MaskOrder, Sz)) {
3842     Order.clear();
3843     return;
3844   }
3845   Order.assign(Sz, Sz);
3846   for (unsigned I = 0; I < Sz; ++I)
3847     if (MaskOrder[I] != PoisonMaskElem)
3848       Order[MaskOrder[I]] = I;
3849   fixupOrderingIndices(Order);
